// Deterministic bucketing. No AI. Uses the run timezone from the Config node.
const cfg = $('Prepare Digest Config').first().json;
const tz = cfg.timezone || 'UTC';
const lookbackH = Number(cfg.lookbackHours) || 24;

// Collect tasks from every input item. Handles a single response or paginated pages.
const tasks = [];
for (const item of $input.all()) {
  const j = item.json || {};
  if (Array.isArray(j.data)) tasks.push(...j.data);
  else if (j.gid || j.name) tasks.push(j);
}

// Today's date as YYYY-MM-DD in the configured timezone.
function ymdInTz(date, timeZone) {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).formatToParts(date);
  const get = (t) => parts.find((p) => p.type === t).value;
  return get('year') + '-' + get('month') + '-' + get('day');
}

const now = new Date();
const todayStr = ymdInTz(now, tz);
const [ty, tm, td] = todayStr.split('-').map(Number);
const todayUTC = Date.UTC(ty, tm - 1, td);
const dow = new Date(todayUTC).getUTCDay(); // 0 Sunday .. 6 Saturday
const daysUntilSunday = (7 - dow) % 7; // through the coming Sunday
const weekEndStr = ymdInTz(new Date(todayUTC + daysUntilSunday * 86400000), 'UTC');
const completedWindowStart = now.getTime() - lookbackH * 3600 * 1000;

const overdue = [];
const dueToday = [];
const dueThisWeek = [];
const unassigned = [];
const completedRecently = [];
const loadByAssignee = {};

function slim(t) {
  return {
    name: t.name || '(unnamed task)',
    assignee: t.assignee && t.assignee.name ? t.assignee.name : null,
    due_on: t.due_on || null,
    url: t.permalink_url || null,
  };
}

for (const t of tasks) {
  const done = t.completed === true;
  if (done) {
    if (t.completed_at && new Date(t.completed_at).getTime() >= completedWindowStart) {
      completedRecently.push(slim(t));
    }
    continue; // completed tasks are not part of open load or the due buckets
  }

  // Open task: count toward per-assignee load and the due buckets.
  const who = t.assignee && t.assignee.name ? t.assignee.name : 'Unassigned';
  loadByAssignee[who] = (loadByAssignee[who] || 0) + 1;
  if (!(t.assignee && t.assignee.name)) unassigned.push(slim(t));

  const due = t.due_on || null;
  if (due) {
    if (due < todayStr) overdue.push(slim(t));
    else if (due === todayStr) dueToday.push(slim(t));
    else if (due <= weekEndStr) dueThisWeek.push(slim(t));
  }
}

// Oldest due date first inside each list.
const byDue = (a, b) => String(a.due_on).localeCompare(String(b.due_on));
overdue.sort(byDue);
dueToday.sort(byDue);
dueThisWeek.sort(byDue);

const perAssignee = Object.entries(loadByAssignee)
  .map(([name, count]) => ({ name, count }))
  .sort((a, b) => b.count - a.count || a.name.localeCompare(b.name));

const openTotal = tasks.filter((t) => t.completed !== true).length;

return [
  {
    json: {
      projectGid: cfg.projectGid,
      timezone: tz,
      todayStr,
      weekEndStr,
      lookbackHours: lookbackH,
      counts: {
        overdue: overdue.length,
        dueToday: dueToday.length,
        dueThisWeek: dueThisWeek.length,
        unassigned: unassigned.length,
        completedRecently: completedRecently.length,
        openTotal,
      },
      overdue,
      dueToday,
      dueThisWeek,
      unassigned,
      completedRecently,
      perAssignee,
    },
  },
];

// Format the deterministic buckets into a Slack Block Kit message. No AI here.
const d = $json;
const MAX_LINKS = 5;

function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

function taskLine(t) {
  const label = esc(t.name);
  const link = t.url ? '<' + t.url + '|' + label + '>' : label;
  const who = t.assignee ? '  ·  ' + esc(t.assignee) : '  ·  _unassigned_';
  const due = t.due_on ? '  ·  due ' + t.due_on : '';
  return '• ' + link + who + due;
}

function bucketSection(title, emoji, list) {
  const heading = '*' + emoji + ' ' + title + ' (' + list.length + ')*';
  if (list.length === 0) {
    return { type: 'section', text: { type: 'mrkdwn', text: heading + '\n_None_' } };
  }
  const shown = list.slice(0, MAX_LINKS).map(taskLine).join('\n');
  const more = list.length > MAX_LINKS ? '\n_+' + (list.length - MAX_LINKS) + ' more_' : '';
  return { type: 'section', text: { type: 'mrkdwn', text: heading + '\n' + shown + more } };
}

const c = d.counts;
const blocks = [];

blocks.push({
  type: 'header',
  text: { type: 'plain_text', text: 'Asana project status: ' + d.todayStr, emoji: true },
});

blocks.push({
  type: 'context',
  elements: [
    {
      type: 'mrkdwn',
      text:
        c.overdue + ' overdue  ·  ' +
        c.dueToday + ' due today  ·  ' +
        c.dueThisWeek + ' due this week  ·  ' +
        c.unassigned + ' unassigned  ·  ' +
        c.completedRecently + ' completed in the last day',
    },
  ],
});

// Optional one-line summary. Only shows if an upstream node set a summaryLine field.
if (d.summaryLine) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '> ' + esc(d.summaryLine) } });
}

blocks.push({ type: 'divider' });
blocks.push(bucketSection('Overdue', '🔴', d.overdue));
blocks.push(bucketSection('Due today', '🟠', d.dueToday));
blocks.push(bucketSection('Due this week', '🟡', d.dueThisWeek));
blocks.push(bucketSection('Unassigned', '⚪', d.unassigned));

if (d.perAssignee && d.perAssignee.length) {
  const lines = d.perAssignee.map((a) => '• ' + esc(a.name) + ': ' + a.count).join('\n');
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Open load by assignee*\n' + lines } });
}

blocks.push({ type: 'divider' });
blocks.push(bucketSection('Completed recently', '✅', d.completedRecently));

blocks.push({
  type: 'context',
  elements: [
    { type: 'mrkdwn', text: 'Deterministic digest  ·  counts computed in n8n  ·  project ' + (d.projectGid || '') },
  ],
});

const fallbackText =
  'Asana project status for ' + d.todayStr + ': ' +
  c.overdue + ' overdue, ' +
  c.dueToday + ' due today, ' +
  c.dueThisWeek + ' due this week, ' +
  c.unassigned + ' unassigned.';

return [{ json: { blockKit: { blocks }, fallbackText } }];
